import{_ as e,o as a,c as s,ag as n}from"./chunks/framework.BDReElpY.js";const g=JSON.parse('{"title":"Arithmetic Operators","description":"","frontmatter":{},"headers":[],"relativePath":"archive/extra/archive/Baseline/03_arithmetic_ops.md","filePath":"archive/extra/archive/Baseline/03_arithmetic_ops.md"}'),l={name:"archive/extra/archive/Baseline/03_arithmetic_ops.md"};function i(r,t,d,o,p,c){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="arithmetic-operators" tabindex="-1">Arithmetic Operators <a class="header-anchor" href="#arithmetic-operators" aria-label="Permalink to &quot;Arithmetic Operators&quot;">​</a></h1><p><strong>Baseline Feature</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented<br><strong>Test:</strong> <code>00_base_feats/03_arithmetic_ops.vx</code></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Vex provides a comprehensive set of arithmetic operators, ranging from standard mathematical operations to high-performance logic like saturation, rotation, and carry-less multiplication.</p><h2 id="standard-arithmetic" tabindex="-1">Standard Arithmetic <a class="header-anchor" href="#standard-arithmetic" aria-label="Permalink to &quot;Standard Arithmetic&quot;">​</a></h2><p>Standard operators behave as expected, with predictable precedence and associativity.</p><table tabindex="0"><thead><tr><th style="text-align:center;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Example</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:center;"><code>+</code></td><td style="text-align:left;">Addition</td><td style="text-align:left;"><code>a + b</code></td><td style="text-align:left;">Adds two operands</td></tr><tr><td style="text-align:center;"><code>-</code></td><td style="text-align:left;">Subtraction</td><td style="text-align:left;"><code>a - b</code></td><td style="text-align:left;">Subtracts right from left</td></tr><tr><td style="text-align:center;"><code>*</code></td><td style="text-align:left;">Multiplication</td><td style="text-align:left;"><code>a * b</code></td><td style="text-align:left;">Multiplies operands</td></tr><tr><td style="text-align:center;"><code>/</code></td><td style="text-align:left;">Division</td><td style="text-align:left;"><code>a / b</code></td><td style="text-align:left;">Divides left by right (truncates for integers)</td></tr><tr><td style="text-align:center;"><code>%</code></td><td style="text-align:left;">Modulo</td><td style="text-align:left;"><code>a % b</code></td><td style="text-align:left;">Returns remainder</td></tr><tr><td style="text-align:center;"><code>-</code></td><td style="text-align:left;">Negation</td><td style="text-align:left;"><code>-a</code></td><td style="text-align:left;">Unary negation</td></tr></tbody></table><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let sum = 10 + 5;       // 15</span></span>
<span class="line"><span>let diff = 10 - 20;     // -10</span></span>
<span class="line"><span>let prod = 6 * 7;       // 42</span></span>
<span class="line"><span>let quot = 7 / 2;       // 3</span></span>
<span class="line"><span>let rem = 7 % 2;        // 1</span></span></code></pre></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Standard integer arithmetic <strong>wraps around</strong> on overflow (two&#39;s complement) in Release builds, but may panic in Debug builds. For safety, use <a href="#saturating-arithmetic">Saturating Arithmetic</a>.</p></div><h2 id="saturating-arithmetic" tabindex="-1">Saturating Arithmetic <a class="header-anchor" href="#saturating-arithmetic" aria-label="Permalink to &quot;Saturating Arithmetic&quot;">​</a></h2><p>Saturating operators constrain results within the type&#39;s valid range instead of overflowing/wrapping. If a value exceeds the maximum, it stays at the maximum.</p><table tabindex="0"><thead><tr><th style="text-align:center;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Example</th><th style="text-align:left;">Behavior on Overflow</th></tr></thead><tbody><tr><td style="text-align:center;">\`+</td><td style="text-align:left;">\`</td><td style="text-align:left;">Saturating Add</td><td style="text-align:left;">\`a +</td></tr><tr><td style="text-align:center;">\`-</td><td style="text-align:left;">\`</td><td style="text-align:left;">Saturating Sub</td><td style="text-align:left;">\`a -</td></tr><tr><td style="text-align:center;">\`*</td><td style="text-align:left;">\`</td><td style="text-align:left;">Saturating Mul</td><td style="text-align:left;">\`a *</td></tr></tbody></table><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let max: u8 = 255;</span></span>
<span class="line"><span>// Standard: Wraps to 0</span></span>
<span class="line"><span>// let x = max + 1; </span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Saturating: Clamps to 255</span></span>
<span class="line"><span>let safe = max +| 1; </span></span>
<span class="line"><span>(safe); // 255</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let min: u8 = 0;</span></span>
<span class="line"><span>let under = min -| 50;</span></span>
<span class="line"><span>(under); // 0 (Does not wrap to 206)</span></span></code></pre></div><h2 id="advanced-simd-operators" tabindex="-1">Advanced &amp; SIMD Operators <a class="header-anchor" href="#advanced-simd-operators" aria-label="Permalink to &quot;Advanced &amp; SIMD Operators&quot;">​</a></h2><p>Vex includes operators specifically designed for cryptography, hashing, and SIMD (Single Instruction, Multiple Data) algorithms.</p><table tabindex="0"><thead><tr><th style="text-align:center;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Example</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:center;"><code>&lt;&lt;&lt;</code></td><td style="text-align:left;">Rotate Left</td><td style="text-align:left;"><code>x &lt;&lt;&lt; 2</code></td><td style="text-align:left;">Bitwise rotation left</td></tr><tr><td style="text-align:center;"><code>&gt;&gt;&gt;</code></td><td style="text-align:left;">Rotate Right</td><td style="text-align:left;"><code>x &gt;&gt;&gt; 2</code></td><td style="text-align:left;">Bitwise rotation right</td></tr><tr><td style="text-align:center;"><code>&lt;?</code></td><td style="text-align:left;">Min</td><td style="text-align:left;"><code>a &lt;? b</code></td><td style="text-align:left;">Returns the smaller value</td></tr><tr><td style="text-align:center;"><code>&gt;?</code></td><td style="text-align:left;">Max</td><td style="text-align:left;"><code>a &gt;? b</code></td><td style="text-align:left;">Returns the larger value</td></tr><tr><td style="text-align:center;"><code>*^</code></td><td style="text-align:left;">Carry-less Mul</td><td style="text-align:left;"><code>a *^ b</code></td><td style="text-align:left;">Galois Field multiplication (AES-GCM)</td></tr></tbody></table><h3 id="rotation-vs-shift" tabindex="-1">Rotation vs Shift <a class="header-anchor" href="#rotation-vs-shift" aria-label="Permalink to &quot;Rotation vs Shift&quot;">​</a></h3><p>Rotation shifts bits out one end and puts them back in the other, preserving all information.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x: u8 = 0b10000001;</span></span>
<span class="line"><span>let rot = x &lt;&lt;&lt; 1; </span></span>
<span class="line"><span>// Result: 0b00000011 (The &#39;1&#39; from MSB moved to LSB)</span></span></code></pre></div><h3 id="min-max" tabindex="-1">Min / Max (<code>&lt;?</code>, <code>&gt;?</code>) <a class="header-anchor" href="#min-max" aria-label="Permalink to &quot;Min / Max (\`&lt;?\`, \`&gt;?\`)&quot;">​</a></h3><p>Optimized intrinsics (often single instruction on x86/ARM).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x = 10;</span></span>
<span class="line"><span>let y = 20;</span></span>
<span class="line"><span>let lower = x &lt;? y; // 10</span></span>
<span class="line"><span>let upper = x &gt;? y; // 20</span></span></code></pre></div><h2 id="real-world-usage" tabindex="-1">Real World Usage <a class="header-anchor" href="#real-world-usage" aria-label="Permalink to &quot;Real World Usage&quot;">​</a></h2><h3 id="_1-signal-processing-saturating-math" tabindex="-1">1. Signal Processing (Saturating Math) <a class="header-anchor" href="#_1-signal-processing-saturating-math" aria-label="Permalink to &quot;1. Signal Processing (Saturating Math)&quot;">​</a></h3><p>When processing audio, you never want a sample to wrap from loud (positive) to inverse extreme (negative), which causes &quot;clipping&quot; noise.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn mix_audio(sample1: i16, sample2: i16) : i16 {</span></span>
<span class="line"><span>    // Standard &#39;+&#39; would cause overflow popping</span></span>
<span class="line"><span>    // Saturating &#39;+|&#39; creates smooth clipping distortion instead</span></span>
<span class="line"><span>    return sample1 +| sample2;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_2-cryptography-rotate-carry-less-mul" tabindex="-1">2. Cryptography (Rotate &amp; Carry-less Mul) <a class="header-anchor" href="#_2-cryptography-rotate-carry-less-mul" aria-label="Permalink to &quot;2. Cryptography (Rotate &amp; Carry-less Mul)&quot;">​</a></h3><p>Hashing algorithms like ChaCha20 or SHA-256 rely heavily on rotation. AES-GCM uses carry-less multiplication.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn encrypt_step(state: u32, key: u32) : u32 {</span></span>
<span class="line"><span>    let mixed = state ^ key;</span></span>
<span class="line"><span>    // Rotate left 13 bits (common in crypto)</span></span>
<span class="line"><span>    return mixed &lt;&lt;&lt; 13;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_3-bounding-boxes-min-max" tabindex="-1">3. Bounding Boxes (Min/Max) <a class="header-anchor" href="#_3-bounding-boxes-min-max" aria-label="Permalink to &quot;3. Bounding Boxes (Min/Max)&quot;">​</a></h3><p>Calculating the intersection of rectangles.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let x_overlap = (rect1.x2 &lt;? rect2.x2) - (rect1.x1 &gt;? rect2.x1);</span></span></code></pre></div>`,32)])])}const x=e(l,[["render",i]]);export{g as __pageData,x as default};
